    10→// SemanticReleasesStore defines the persistence operations for semantic releases.
    11→type SemanticReleasesStore interface {
    12→	ListAllSemanticReleases(ctx context.Context, page, perPage int) ([]models.SemanticRelease, int, error)
    13→	ListSemanticReleases(ctx context.Context, projectID string, page, perPage int) ([]models.SemanticRelease, int, error)
    14→	GetSemanticRelease(ctx context.Context, id string) (*models.SemanticRelease, error)
    15→	GetSemanticReleaseSources(ctx context.Context, id string) ([]models.Release, error)
    16→	DeleteSemanticRelease(ctx context.Context, id string) error
    17→}
    18→
    19→// SemanticReleasesHandler implements HTTP handlers for the /semantic-releases resource.
    20→type SemanticReleasesHandler struct {
    21→	store SemanticReleasesStore
    22→}
    23→
    24→// NewSemanticReleasesHandler returns a new SemanticReleasesHandler.
    25→func NewSemanticReleasesHandler(store SemanticReleasesStore) *SemanticReleasesHandler {
    26→	return &SemanticReleasesHandler{store: store}
    27→}
    28→
    29→// ListAll handles GET /semantic-releases — returns all semantic releases across all projects.
    30→func (h *SemanticReleasesHandler) ListAll(w http.ResponseWriter, r *http.Request) {
    31→	page, perPage := ParsePagination(r)
    32→	releases, total, err := h.store.ListAllSemanticReleases(r.Context(), page, perPage)
    33→	if err != nil {
    34→		RespondError(w, r, http.StatusInternalServerError, "internal_error", "Failed to list semantic releases")
    35→		return
    36→	}
    37→	if releases == nil {
    38→		releases = []models.SemanticRelease{}
    39→	}
    40→	RespondList(w, r, http.StatusOK, releases, page, perPage, total)
    41→}
    42→
    43→// List handles GET /projects/{projectId}/semantic-releases — returns a paginated list of semantic releases for a project.
    44→func (h *SemanticReleasesHandler) List(w http.ResponseWriter, r *http.Request) {
    45→	projectID := r.PathValue("projectId")
    46→	if projectID == "" {
    47→		RespondError(w, r, http.StatusBadRequest, "bad_request", "Project ID is required")
    48→		return
    49→	}
    50→	page, perPage := ParsePagination(r)
    51→	releases, total, err := h.store.ListSemanticReleases(r.Context(), projectID, page, perPage)
    52→	if err != nil {
    53→		RespondError(w, r, http.StatusInternalServerError, "internal_error", "Failed to list semantic releases")
    54→		return
    55→	}
    56→	if releases == nil {
    57→		releases = []models.SemanticRelease{}
    58→	}
    59→	RespondList(w, r, http.StatusOK, releases, page, perPage, total)
    60→}
    61→
    62→// Get handles GET /semantic-releases/{id} — returns a single semantic release.
    63→func (h *SemanticReleasesHandler) Get(w http.ResponseWriter, r *http.Request) {
    64→	id := r.PathValue("id")
    65→	if id == "" {
    66→		RespondError(w, r, http.StatusBadRequest, "bad_request", "Semantic release ID is required")
    67→		return
    68→	}
    69→	sr, err := h.store.GetSemanticRelease(r.Context(), id)
    70→	if err != nil {
    71→		RespondError(w, r, http.StatusNotFound, "not_found", "Semantic release not found")
    72→		return
    73→	}
    74→	RespondJSON(w, r, http.StatusOK, sr)
    75→}
    76→
    77→// ListSources handles GET /semantic-releases/{id}/sources — returns source releases linked to this semantic release.
    78→func (h *SemanticReleasesHandler) ListSources(w http.ResponseWriter, r *http.Request) {
    79→	id := r.PathValue("id")
    80→	if id == "" {
    81→		RespondError(w, r, http.StatusBadRequest, "bad_request", "Semantic release ID is required")
    82→		return
    83→	}
    84→	releases, err := h.store.GetSemanticReleaseSources(r.Context(), id)
    85→	if err != nil {
    86→		RespondError(w, r, http.StatusNotFound, "not_found", "Semantic release not found")
    87→		return
    88→	}
    89→	if releases == nil {
    90→		releases = []models.Release{}
    91→	}
    92→	RespondJSON(w, r, http.StatusOK, releases)
    93→}
    94→
    95→// Delete handles DELETE /semantic-releases/{id} — deletes a single semantic release.
    96→func (h *SemanticReleasesHandler) Delete(w http.ResponseWriter, r *http.Request) {
    97→	id := r.PathValue("id")
    98→	if id == "" {
    99→		RespondError(w, r, http.StatusBadRequest, "bad_request", "Semantic release ID is required")
   100→		return
   101→	}
   102→	if err := h.store.DeleteSemanticRelease(r.Context(), id); err != nil {
   103→		RespondError(w, r, http.StatusNotFound, "not_found", "Semantic release not found")
   104→		return
   105→	}
   106→	w.WriteHeader(http.StatusNoContent)
   107→}
