     1→// web/lib/api/types.ts
     2→
     3→// --- Response Envelope ---
     4→
     5→export interface ApiResponse<T> {
     6→  data: T;
     7→  meta?: ApiMeta;
     8→  error?: ApiError;
     9→}
    10→
    11→export interface ApiMeta {
    12→  page: number;
    13→  per_page: number;
    14→  total: number;
    15→}
    16→
    17→export interface ApiError {
    18→  code: string;
    19→  message: string;
    20→}
    21→
    22→// --- Domain Models (all IDs are UUID strings) ---
    23→
    24→export interface Project {
    25→  id: string;
    26→  name: string;
    27→  description?: string;
    28→  agent_prompt?: string;
    29→  agent_rules?: AgentRules;
    30→  created_at: string;
    31→  updated_at: string;
    32→}
    33→
    34→export interface AgentRules {
    35→  on_major_release?: boolean;
    36→  on_minor_release?: boolean;
    37→  on_security_patch?: boolean;
    38→  version_pattern?: string;
    39→}
    40→
    41→export interface ProjectInput {
    42→  name: string;
    43→  description?: string;
    44→  agent_prompt?: string;
    45→  agent_rules?: AgentRules;
    46→}
    47→
    48→export interface Source {
    49→  id: string;
    50→  project_id: string;
    51→  provider: string;
    52→  repository: string;
    53→  poll_interval_seconds: number;
    54→  enabled: boolean;
    55→  config?: Record<string, unknown>;
    56→  version_filter_include?: string;
    57→  version_filter_exclude?: string;
    58→  exclude_prereleases?: boolean;
    59→  last_polled_at?: string;
    60→  last_error?: string;
    61→  created_at: string;
    62→  updated_at: string;
    63→}
    64→
    65→export interface SourceInput {
    66→  provider: string;
    67→  repository: string;
    68→  poll_interval_seconds: number;
    69→  enabled: boolean;
    70→  config?: Record<string, unknown>;
    71→  version_filter_include?: string;
    72→  version_filter_exclude?: string;
    73→  exclude_prereleases?: boolean;
    74→}
    75→
    76→export interface Release {
    77→  id: string;
    78→  source_id: string;
    79→  version: string;
    80→  raw_data?: Record<string, unknown>;
    81→  released_at?: string;
    82→  created_at: string;
    83→  project_id?: string;
    84→  project_name?: string;
    85→  provider?: string;
    86→  repository?: string;
    87→}
    88→
    89→export interface ContextSource {
    90→  id: string;
    91→  project_id: string;
    92→  type: string;
    93→  name: string;
    94→  config: Record<string, unknown>;
    95→  created_at: string;
    96→  updated_at: string;
    97→}
    98→
    99→export interface ContextSourceInput {
   100→  type: string;
   101→  name: string;
   102→  config: Record<string, unknown>;
   103→}
   104→
   105→export interface SemanticRelease {
   106→  id: string;
   107→  project_id: string;
   108→  version: string;
   109→  report?: SemanticReport;
   110→  status: string;
   111→  error?: string;
   112→  created_at: string;
   113→  completed_at?: string;
   114→}
   115→
   116→export interface SemanticReport {
   117→  subject?: string;
   118→  risk_level?: string;
   119→  risk_reason?: string;
   120→  status_checks?: string[];
   121→  changelog_summary?: string;
   122→  download_commands?: string[];
   123→  download_links?: string[];
   124→  summary?: string;
   125→  availability?: string;
   126→  adoption?: string;
   127→  urgency?: string;
   128→  recommendation?: string;
   129→}
   130→
   131→export interface AgentRun {
   132→  id: string;
   133→  project_id: string;
   134→  semantic_release_id?: string;
   135→  trigger: string;
   136→  status: string;
   137→  prompt_used?: string;
   138→  error?: string;
   139→  started_at?: string;
   140→  completed_at?: string;
   141→  created_at: string;
   142→}
   143→
   144→export interface NotificationChannel {
