"use client";

import { useState, Suspense } from "react";
import { useSearchParams } from "next/navigation";
import useSWR from "swr";
import Link from "next/link";
import {
  semanticReleases as srApi,
  projects as projectsApi,
} from "@/lib/api/client";
import { VersionChip } from "@/components/ui/version-chip";
import { ConfirmDialog } from "@/components/ui/confirm-dialog";
import { Trash2 } from "lucide-react";
import { timeAgo } from "@/lib/format";
import type { Project, SemanticRelease } from "@/lib/api/types";

/* ---------- Urgency chip ---------- */

const URGENCY_COLORS: Record<string, { bg: string; text: string }> = {
  critical: { bg: "#dc2626", text: "#ffffff" },
  high: { bg: "#f97316", text: "#ffffff" },
  medium: { bg: "#f59e0b", text: "#ffffff" },
  low: { bg: "#6b7280", text: "#ffffff" },
};

function UrgencyChip({ urgency }: { urgency: string }) {
  const u = urgency.toLowerCase();
  const style = URGENCY_COLORS[u];
  if (!style) return null;
  return (
    <span
      className="inline-flex items-center rounded-full px-2 py-0.5 text-[11px] font-medium leading-none"
      style={{ backgroundColor: style.bg, color: style.text }}
    >
      {urgency}
    </span>
  );
}

/* ---------- Helpers ---------- */

const PER_PAGE = 15;

/* ---------- Main component ---------- */

export function SemanticReleasesList() {
  return (
    <Suspense>
      <SemanticReleasesListInner />
    </Suspense>
  );
}

function SemanticReleasesListInner() {
  const searchParams = useSearchParams();
  const initialProject = searchParams.get("project") ?? "all";
  const [page, setPage] = useState(1);
  const [projectFilter, setProjectFilter] = useState<string>(initialProject);
  const [deletingId, setDeletingId] = useState<string | null>(null);

  /* Fetch projects for the filter dropdown */
  const { data: projectsData } = useSWR("projects-for-sr-filter", () =>
    projectsApi.list()
  );
  const projectsById = new Map<string, Project>();
  for (const p of projectsData?.data ?? []) projectsById.set(p.id, p);

  /* Fetch semantic releases — scoped by project or all */
  const { data: scopedData, isLoading: scopedLoading, mutate: mutateScopedData } = useSWR(
    projectFilter !== "all" ? ["sr-scoped", page, projectFilter] : null,
    () => srApi.list(projectFilter, page, PER_PAGE)
  );

  const { data: allData, isLoading: allLoading, mutate: mutateAllData } = useSWR(
    projectFilter === "all" ? ["sr-all", page] : null,
    () => srApi.listAll(page, PER_PAGE)
  );

  const isLoading = projectFilter !== "all" ? scopedLoading : allLoading;
  const releases: SemanticRelease[] =
    projectFilter !== "all"
      ? scopedData?.data ?? []
      : allData?.data ?? [];

  const mutateData = projectFilter !== "all" ? mutateScopedData : mutateAllData;

  /* Pagination math */
  const activeData = projectFilter !== "all" ? scopedData : allData;
  const total = activeData?.meta?.total ?? 0;
  const totalPages = Math.max(1, Math.ceil(total / PER_PAGE));
  const startRow = (page - 1) * PER_PAGE + 1;
  const endRow = Math.min(page * PER_PAGE, total);

  return (
    <div className="space-y-6 fade-in">
      {/* Page title */}
      <h1
        style={{
          fontFamily: "var(--font-fraunces)",
          fontSize: "24px",
          fontWeight: 700,
          color: "#111113",
        }}
      >
        Semantic Releases
      </h1>

      {/* Project filter */}
      <div>
        <select
          value={projectFilter}
          onChange={(e) => {
            setProjectFilter(e.target.value);
            setPage(1);
          }}
          className="appearance-none rounded-md bg-white px-3 py-2 pr-8 outline-none transition-shadow"
          style={{
            fontFamily: "var(--font-dm-sans)",
            fontSize: "13px",
            color: "#111113",
            border: "1px solid #e8e8e5",
          }}
          onFocus={(e) =>
            (e.currentTarget.style.boxShadow = "0 0 0 2px #e8601a40")
          }
          onBlur={(e) => (e.currentTarget.style.boxShadow = "none")}
        >
          <option value="all">All Projects</option>
          {projectsData?.data.map((p: Project) => (
            <option key={p.id} value={p.id}>
              {p.name}
            </option>
          ))}
        </select>
      </div>

      {/* Table card */}
      <div
        className="overflow-hidden rounded-lg bg-white"
        style={{ border: "1px solid #e8e8e5" }}
      >
        {isLoading ? (
          <div
            className="py-16 text-center"
            style={{
              fontFamily: "var(--font-dm-sans)",
              fontSize: "13px",
              color: "#6b7280",
            }}
          >
            Loading...
          </div>
        ) : releases.length === 0 ? (
          <div className="py-16 text-center">
            <p
              style={{
                fontFamily: "var(--font-fraunces)",
                fontStyle: "italic",
                fontSize: "15px",
                color: "#9ca3af",
              }}
            >
              No semantic releases yet
            </p>
          </div>
        ) : (
          <table className="w-full">
            <thead>
              <tr style={{ borderBottom: "1px solid #e8e8e5", backgroundColor: "#fafaf9" }}>
                {["Project", "Version", "Status", "Urgency", "Age", ""].map(
                  (col) => (
                    <th
                      key={col}
                      className="px-4 py-3 text-left"
                      style={{
                        fontFamily: "var(--font-dm-sans)",
                        fontSize: "11px",
                        fontWeight: 600,
                        textTransform: "uppercase" as const,
                        letterSpacing: "0.08em",
                        color: "#9ca3af",
                      }}
                    >
                      {col}
                    </th>
                  )
                )}
              </tr>
            </thead>
            <tbody>
              {releases.map((sr) => {
                const project = projectsById.get(sr.project_id);
                return (
                  <tr
                    key={sr.id}
                    className="transition-colors hover:bg-[#fafaf9]"
                    style={{ borderBottom: "1px solid #e8e8e5" }}
                  >
                    {/* Project */}
                    <td className="px-4 py-3">
                      {project ? (
                        <Link
                          href={`/projects/${project.id}`}
                          className="hover:underline"
                          style={{
                            fontFamily: "var(--font-dm-sans)",
                            fontSize: "13px",
                            color: "#111113",
                            fontWeight: 500,
                          }}
                        >
                          {project.name}
                        </Link>
                      ) : (
                        <span
                          style={{
                            fontFamily: "var(--font-dm-sans)",
                            fontSize: "13px",
                            color: "#9ca3af",
                          }}
                        >
                          {"\u2014"}
                        </span>
                      )}
                    </td>

                    {/* Version */}
                    <td className="px-4 py-3">
                      <Link href={`/projects/${sr.project_id}/semantic-releases/${sr.id}`}>
                        <VersionChip version={sr.version} />
                      </Link>
                    </td>

                    {/* Status */}
                    <td className="px-4 py-3">
                      <span
                        className="text-[13px] font-medium"
                        style={{
                          fontFamily: "var(--font-dm-sans)",
                          color: sr.status === "completed" ? "#16a34a" : "#e8601a",
                        }}
                      >
                        {sr.status}
                      </span>
                    </td>

                    {/* Urgency */}
                    <td className="px-4 py-3">
                      {sr.report?.urgency ? (
                        <UrgencyChip urgency={sr.report.urgency} />
                      ) : (
                        <span
                          style={{
                            fontFamily: "var(--font-dm-sans)",
                            fontSize: "13px",
                            color: "#9ca3af",
                          }}
                        >
                          {"\u2014"}
                        </span>
                      )}
                    </td>

                    {/* Age */}
                    <td className="px-4 py-3">
                      <span
                        style={{
                          fontFamily: "var(--font-dm-sans)",
                          fontSize: "13px",
                          color: "#9ca3af",
                        }}
                      >
                        {timeAgo(sr.completed_at ?? sr.created_at)}
                      </span>
                    </td>

                    {/* Delete */}
                    <td className="px-4 py-3">
                      <button
                        onClick={() => setDeletingId(sr.id)}
                        className="rounded p-1 transition-colors hover:bg-red-50 hover:text-red-600"
                        style={{ color: "#9ca3af" }}
                        title="Delete semantic release"
                      >
                        <Trash2 className="h-4 w-4" />
                      </button>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        )}
      </div>

      {/* Pagination */}
      {total > 0 && (
        <div className="flex items-center justify-between">
          <span
            style={{
              fontFamily: "var(--font-dm-sans)",
              fontSize: "13px",
              color: "#9ca3af",
            }}
          >
            {startRow}&ndash;{endRow} of {total}
          </span>
          <div className="flex items-center gap-2">
            <button
              disabled={page <= 1}
              onClick={() => setPage(page - 1)}
              className="rounded-md bg-white px-3 py-1.5 transition-colors hover:bg-[#fafaf9] disabled:cursor-not-allowed disabled:opacity-40"
              style={{
                fontFamily: "var(--font-dm-sans)",
                fontSize: "13px",
                color: "#374151",
                border: "1px solid #e8e8e5",
              }}
            >
              Previous
            </button>
            <button
              disabled={page >= totalPages}
              onClick={() => setPage(page + 1)}
              className="rounded-md bg-white px-3 py-1.5 transition-colors hover:bg-[#fafaf9] disabled:cursor-not-allowed disabled:opacity-40"
              style={{
                fontFamily: "var(--font-dm-sans)",
                fontSize: "13px",
                color: "#374151",
                border: "1px solid #e8e8e5",
              }}
            >
              Next
            </button>
          </div>
        </div>
      )}

      {/* Delete confirmation */}
      <ConfirmDialog
        open={!!deletingId}
        onOpenChange={(open) => {
          if (!open) setDeletingId(null);
        }}
        title="Delete Semantic Release"
        description="This will permanently delete this semantic release and its report."
        onConfirm={async () => {
          if (deletingId) {
            await srApi.delete(deletingId);
            mutateData();
          }
        }}
      />
    </div>
  );
}

// web/lib/api/client.ts
import type {
  ApiResponse,
  Project,
  ProjectInput,
  Release,
  Source,
  SourceInput,
  Subscription,
  SubscriptionInput,
  BatchSubscriptionInput,
  BatchDeleteSubscriptionInput,
  NotificationChannel,
  ChannelInput,
  ContextSource,
  ContextSourceInput,
  SemanticRelease,
  AgentRun,
  HealthStatus,
  Stats,
  TrendData,
} from "./types";

const BASE = process.env.NEXT_PUBLIC_API_URL || "/api/v1";

async function request<T>(path: string, init?: RequestInit): Promise<T> {
  const res = await fetch(`${BASE}${path}`, {
    headers: { "Content-Type": "application/json", ...init?.headers },
    ...init,
  });
  if (!res.ok) {
    const body = await res.json().catch(() => null);
    throw new Error(body?.error?.message ?? `Request failed: ${res.status}`);
  }
  if (res.status === 204) return null as T;
  return res.json();
}

// --- Projects ---

export const projects = {
  list: (page = 1, perPage = 25) =>
    request<ApiResponse<Project[]>>(`/projects?page=${page}&per_page=${perPage}`),
  get: (id: string) =>
    request<ApiResponse<Project>>(`/projects/${id}`),
  create: (input: ProjectInput) =>
    request<ApiResponse<Project>>("/projects", {
      method: "POST",
      body: JSON.stringify(input),
    }),
  update: (id: string, input: ProjectInput) =>
    request<ApiResponse<Project>>(`/projects/${id}`, {
      method: "PUT",
      body: JSON.stringify(input),
    }),
  delete: (id: string) =>
    request<ApiResponse<null>>(`/projects/${id}`, { method: "DELETE" }),
};

// --- Sources (nested under projects) ---

export const sources = {
  listByProject: (projectId: string, page = 1) =>
    request<ApiResponse<Source[]>>(`/projects/${projectId}/sources?page=${page}`),
  create: (projectId: string, input: SourceInput) =>
    request<ApiResponse<Source>>(`/projects/${projectId}/sources`, {
      method: "POST",
      body: JSON.stringify(input),
    }),
  get: (id: string) =>
    request<ApiResponse<Source>>(`/sources/${id}`),
  update: (id: string, input: SourceInput) =>
    request<ApiResponse<Source>>(`/sources/${id}`, {
      method: "PUT",
      body: JSON.stringify(input),
    }),
  delete: (id: string) =>
    request<ApiResponse<null>>(`/sources/${id}`, { method: "DELETE" }),
  poll: (id: string) =>
    request<ApiResponse<{ new_releases: number }>>(`/sources/${id}/poll`, {
      method: "POST",
    }),
};

export const releases = {
  list: (page = 1, perPage = 25) =>
    request<ApiResponse<Release[]>>(`/releases?page=${page}&per_page=${perPage}`),
  listBySource: (sourceId: string, page = 1) =>
    request<ApiResponse<Release[]>>(`/sources/${sourceId}/releases?page=${page}`),
  listByProject: (projectId: string, page = 1, perPage = 25) =>
    request<ApiResponse<Release[]>>(`/projects/${projectId}/releases?page=${page}&per_page=${perPage}`),
  get: (id: string) =>
    request<ApiResponse<Release>>(`/releases/${id}`),
};

// --- Context Sources ---

export const contextSources = {
  list: (projectId: string, page = 1) =>
    request<ApiResponse<ContextSource[]>>(`/projects/${projectId}/context-sources?page=${page}`),
  create: (projectId: string, input: ContextSourceInput) =>
    request<ApiResponse<ContextSource>>(`/projects/${projectId}/context-sources`, {
      method: "POST",
      body: JSON.stringify(input),
    }),
  get: (id: string) =>
    request<ApiResponse<ContextSource>>(`/context-sources/${id}`),
  update: (id: string, input: ContextSourceInput) =>
    request<ApiResponse<ContextSource>>(`/context-sources/${id}`, {
      method: "PUT",
      body: JSON.stringify(input),
    }),
  delete: (id: string) =>
    request<ApiResponse<null>>(`/context-sources/${id}`, { method: "DELETE" }),
};

// --- Semantic Releases ---

export const semanticReleases = {
  listAll: (page = 1, perPage = 25) =>
    request<ApiResponse<SemanticRelease[]>>(`/semantic-releases?page=${page}&per_page=${perPage}`),
  list: (projectId: string, page = 1, perPage = 25) =>
    request<ApiResponse<SemanticRelease[]>>(`/projects/${projectId}/semantic-releases?page=${page}&per_page=${perPage}`),
  get: (id: string) =>
    request<ApiResponse<SemanticRelease>>(`/semantic-releases/${id}`),
  delete: (id: string) =>
    request<ApiResponse<null>>(`/semantic-releases/${id}`, { method: "DELETE" }),
  getSources: (id: string) =>
    request<ApiResponse<Release[]>>(`/semantic-releases/${id}/sources`),
};

// --- Agent ---

export const agent = {
  triggerRun: (projectId: string, version?: string) =>
    request<ApiResponse<AgentRun>>(`/projects/${projectId}/agent/run`, {
      method: "POST",
      body: JSON.stringify({ trigger: "test", version: version || undefined }),
    }),
  listRuns: (projectId: string, page = 1) =>
    request<ApiResponse<AgentRun[]>>(`/projects/${projectId}/agent/runs?page=${page}`),
  getRun: (id: string) =>
    request<ApiResponse<AgentRun>>(`/agent-runs/${id}`),
};

// --- Subscriptions ---

export const subscriptions = {
  list: (page = 1, perPage = 100) =>
    request<ApiResponse<Subscription[]>>(`/subscriptions?page=${page}&per_page=${perPage}`),
  get: (id: string) => request<ApiResponse<Subscription>>(`/subscriptions/${id}`),
  create: (input: SubscriptionInput) =>
    request<ApiResponse<Subscription>>("/subscriptions", {
      method: "POST",
      body: JSON.stringify(input),
    }),
  batchCreate: (input: BatchSubscriptionInput) =>
    request<ApiResponse<Subscription[]>>("/subscriptions/batch", {
      method: "POST",
      body: JSON.stringify(input),
    }),
  update: (id: string, input: SubscriptionInput) =>
    request<ApiResponse<Subscription>>(`/subscriptions/${id}`, {
      method: "PUT",
      body: JSON.stringify(input),
    }),
  delete: (id: string) =>
    request<ApiResponse<null>>(`/subscriptions/${id}`, { method: "DELETE" }),
  batchDelete: (input: BatchDeleteSubscriptionInput) =>
    request<ApiResponse<null>>("/subscriptions/batch", {
      method: "DELETE",
      body: JSON.stringify(input),
    }),
};

// --- Notification Channels ---

export const channels = {
  list: (page = 1, perPage = 100) =>
    request<ApiResponse<NotificationChannel[]>>(`/channels?page=${page}&per_page=${perPage}`),
  get: (id: string) => request<ApiResponse<NotificationChannel>>(`/channels/${id}`),
  create: (input: ChannelInput) =>
    request<ApiResponse<NotificationChannel>>("/channels", {
      method: "POST",
      body: JSON.stringify(input),
    }),
  update: (id: string, input: ChannelInput) =>
    request<ApiResponse<NotificationChannel>>(`/channels/${id}`, {
      method: "PUT",
      body: JSON.stringify(input),
    }),
  delete: (id: string) =>
    request<ApiResponse<null>>(`/channels/${id}`, { method: "DELETE" }),
  test: (id: string) =>
    request<ApiResponse<{ status: string }>>(`/channels/${id}/test`, {
      method: "POST",
    }),
};

// --- System ---

export const system = {
  health: () => request<HealthStatus>("/health"),
  stats: () => request<ApiResponse<Stats>>("/stats"),
  trend: (granularity: "daily" | "weekly" | "monthly" = "daily", days = 7) =>
    request<ApiResponse<TrendData>>(`/stats/trend?granularity=${granularity}&days=${days}`),
};

